function gen_otp(mobile, res, successCallback, errorCallback) {
  let otp = Math.floor(Math.random() * (999999 - 111111 + 1)) + 111111;
  let where = {};
  where["otp"] = otp;
  Users.findOne(where).then((response) => {
    if (response == null) {
      let where = {};
      where["mobile"] = mobile;
      where["deleted"] = 0;
      Users.findOneAndUpdate(where, { otp: otp }, { new: true })
        .exec()
        .then(() => {
          axios
            .get(
              "https://2factor.in/API/V1/d4ab2eaa-d61e-11ea-9fa5-0200cd936042/SMS/" +
                mobile +
                "/" +
                otp +
                "/AUTO_FETCH_OTP",
              {}
            )
            .then(function () {
              ////console.log(response.data);
              successCallback(otp);
            })
            .catch(function (error) {
              res.status(200).send({
                status: "error",
                message: error.message,
              });
            });
        })
        .catch(() => {
          gen_otp(mobile, res);
        });
    } else {
      gen_otp(mobile, res);
    }
  });
}

