  user_list: function (req, res) {
    // Users.aggregate([{ $group: { _id: "$user_type", num_tutorial: { $sum: 1 } } }]).then((response) => {
    //     console.log(response);
    // });

    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};

      if (req.query.user && req.query.user != "") {
        // where["$or"] = [
        //  // { full_name: { $regex: ".*" + req.query.user, $options: "i" } },
        //   { email: { $regex: ".*" + req.query.user, $options: "i" } },
        //   { mobile: { $regex: ".*" + req.query.user, $options: "i" } },
        // ];
        where["mobile"] = {
          $regex: ".*" + req.query.user,
          $options: "i",
        };
      }

      if (req.query.group && req.query.group != "") {
        where["role"] = req.query.group;
      } else {
        where["user_type"] = {
          $nin: [
            "customer",
            "vendor",
            "cargo_partner",
            "pickup_boy",
            "lp_manager",
            "pickup_partner",
            "lp_head",
            "delivery_partner",
            "delivery_boy",
            "lp_head",
          ],
        };
        // where["$or"] = [
        //     {
        //         user_type: "admin",
        //     },
        //     {
        //         user_type: "customer_support",
        //     },
        //     {
        //         user_type: "city_executive",
        //     },
        //     {
        //         user_type: "c_editor",
        //     },
        //     {
        //         user_type: "operations",
        //     },
        //     {
        //         user_type: "center_head",
        //     },
        //     {
        //         user_type: "accountant",
        //     },
        //     {
        //         user_type: 0,
        //     },
        // ];
      }

      if (req.query.active != "") {
        where["active"] = req.query.active;
      }

      where["deleted"] = 0;

      Users.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .populate("role")
        .sort({
          created_date: -1,
        })
        .then((response) => {
          Users.find(where).countDocuments(function (err, count) {
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },

  update_user_status: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      return res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    }

    const where = { _id: req.body.id };

    Users.findOne(where)
      .then((response) => {
        if (!response) {
          return res.status(200).send({
            status: "error",
            message: "User not found",
            token: req.token,
          });
        }

        const active = response.active === 0 ? 1 : 0;

        Users.findOneAndUpdate(where, { active: active }, { new: true })
          .exec()
          .then((updatedUser) => {
            res.status(200).send({
              status: "success",
              message: "Status updated",
              token: req.token,
              active: active,
            });
          })
          .catch((error) => {
            res.status(200).send({
              status: "error",
              message: "Something went wrong",
              token: req.token,
            });
          });
      })
      .catch((error) => {
        res.status(200).send({
          status: "error",
          message: "Something went wrong",
          token: req.token,
        });
      });
  },

