  update_brand: async function (req, res) {
    try {
      const {
        name,
        id,
        desc,
        short_desc,
        seo_title,
        seo_description,
        seo_keywords,
      } = req.query;

      // Validate required fields
      if (!name)
        return res
          .status(400)
          .send({
            status: "error",
            message: "Enter brand name",
            token: req.token,
          });
      if (!id)
        return res
          .status(400)
          .send({
            status: "error",
            message: "Enter brand id",
            token: req.token,
          });

      // Prepare the update object
      const updateData = {
        name,
        desc,
        short_desc,
        update_date: moment().format(),
        seo_title,
        seo_description,
        seo_keywords,
      };

      // Handle file upload if present
      await new Promise((resolve, reject) => {
        upload_local(req, res, (error) => (error ? reject(error) : resolve()));
      });

      if (req.files && req.files.length > 0) {
        const file = req.files[0];
        updateData.file = `https://${req.get("host")}/images/${file.filename}`;
      }

      // Update the brand in the database
      const updatedBrand = await Brand.findOneAndUpdate(
        { _id: id },
        updateData,
        { new: true }
      ).exec();

      if (updatedBrand) {
        return res
          .status(200)
          .send({
            status: "success",
            message: "Brand has been updated",
            token: req.token,
          });
      } else {
        return res
          .status(404)
          .send({
            status: "error",
            message: "Brand not found",
            token: req.token,
          });
      }
    } catch (error) {
      console.error("Error updating brand:", error);
      return res
        .status(500)
        .send({
          status: "error",
          message: "Internal server error",
          token: req.token,
        });
    }
  },

