  update_vendor: async function (req, res) {
    try {
      // Validate vendor name
      if (!req.query.name || req.query.name.trim() === "") {
        return res.status(400).send({
          status: "error",
          message: "Enter vendor name",
          token: req.token,
        });
      }

      // Validate vendor ID
      if (!req.query.id || req.query.id.trim() === "") {
        return res.status(400).send({
          status: "error",
          message: "Enter vendor ID",
          token: req.token,
        });
      }

      // Handle file upload
      upload_local(req, res, async (error) => {
        if (error) {
          return res.status(400).send({
            status: "error",
            message: error.message || "File upload failed",
            token: req.token,
          });
        }

        // Prepare update data
        const updatedata = {
          city: req.query.city,
          full_name: req.query.name,
          slug: req.query.slug,
          about: req.query.about,
          note: req.query.note,
          email: req.query.email,
          mobile: req.query.mobile,
          commission_type: req.query.commission_type,
          commission: req.query.commission,
          seo_title: req.query.seo_title,
          seo_desc: req.query.seo_desc,
          delivery_city: req.body.delivery_city
            ? req.body.delivery_city.split(",")
            : [],
          communication_zipcode: req.query.communication_zipcode,
          service_zipcode: req.query.service_zipcode,
          address: req.query.address,
          update_date: moment().format(),
        };

        // Attach file data if a file is uploaded
        if (req.files && req.files.length > 0) {
          const file = req.files[0]; // Get the first file
          updatedata.file = `https://${req.get("host")}/images/${
            file.filename
          }`;
        }

        // Update user in the database
        const updatedUser = await Users.findOneAndUpdate(
          { _id: req.query.id },
          updatedata,
          { new: true }
        );

        if (!updatedUser) {
          return res.status(404).send({
            status: "error",
            message: "User not found",
            token: req.token,
          });
        }

        res.status(200).send({
          status: "success",
          message: "User has been updated",
          token: req.token,
        });
      });
    } catch (error) {
      console.error("Error updating vendor:", error);
      res.status(500).send({
        status: "error",
        message: "Internal Server Error",
        token: req.token,
      });
    }
  },

