  update_settings: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      upload_local(req, res, function (error) {
        if (error) {
          res.status(200).send({
            status: "error",
            message: error.code,
            token: req.token,
          });
        } else {
          if (req.files[0]) {
            let where = {};
            where["_id"] = req.body.id;

            update_data = {};

            const file = req.files[0]; // Get the first (and only) file from the array
            const image_data = {
              fieldname: file.fieldname,
              originalname: file.originalname,
              encoding: file.encoding,
              mimetype: file.mimetype,
              filename: file.filename,
              location: `https://${req.get("host")}/images/${file.filename}`, // Construct the location URL
              size: file.size,
            };

            update_data["value"] = image_data.location;

            Settings.findOneAndUpdate(where, update_data, {
              new: true,
            })
              .exec()
              .then(() => {
                res.status(200).send({
                  status: "success",
                  message: "Settings updated",
                  token: req.token,
                });
              })
              .catch(() => {
                res.status(200).send({
                  status: "error",
                  message: "Something went wrong",
                  token: req.token,
                });
              });
          } else {
            let where = {};
            where["_id"] = req.body.id;

            update_data = {};
            update_data["value"] = req.body.page_value;

            Settings.findOneAndUpdate(where, update_data, {
              new: true,
            })
              .exec()
              .then(() => {
                res.status(200).send({
                  status: "success",
                  message: "Settings updated",
                  token: req.token,
                });
              })
              .catch(() => {
                res.status(200).send({
                  status: "error",
                  message: "Something went wrong",
                  token: req.token,
                });
              });
          }
          // res.status(200).send({
          //   message: req.files[0].location
          // });
        }
      });
    }
  },

