  add_product: function (req, res) {
    multi_upload(req, res, function (error) {
      if (error) {
        res.status(200).send({
          status: "error",
          message: error.code,
          token: req.token,
        });
      } else {
        if (!req.body.name || req.body.name == "") {
          res.status(200).send({
            status: "error",
            message: "Enter product name",
            token: req.token,
          });
          return;
        }

        if (req.files.length > 0) {
          let where = {};
          where["name"] = req.body.name;
          where["deleted"] = 0;
          Products.findOne(where).then((response) => {
            if (response != null) {
              res.status(200).send({
                status: "error",
                message: "Product exist in the database.",
                token: req.token,
              });
            } else {
              let ProductsData = new Products({
                combo_products: req.body.combo_products
                  ? req.body.combo_products.split(",")
                  : null,
                city: req.body.city,
                name: req.body.name,
                category: req.body.category,
                sub_category: req.body.sub_category,
                cuisine: req.body.cuisine,
                brand: req.body.brand,
                vendor: req.body.vendor,
                desc: req.body.desc,
                short_desc: req.body.short_desc,
                price: Number(req.body.price),
                file: req.files,
                express: req.body.express == 1 ? true : false,
                city: req.body.city,
                selling_price: req.body.selling_price,
                batchno: req.body.batchno,
                commission: req.body.commission,
                packaging_charge: req.body.packaging_charge,
                tax_status: req.body.tax_status,
                cgst: req.body.cgst,
                sgst: req.body.sgst,
                igst: req.body.igst,
                sku: req.body.sku,
                stock_qty: req.body.stock_qty,
                backorders: req.body.backorders,
                threshold: req.body.threshold,
                manage_stock: req.body.manage_stock ? req.body.manage_stock : 0,
                weight: req.body.weight,
                length: req.body.lengthh,
                width: req.body.width,
                height: req.body.height,
                shipping: req.body.shipping,
                attribute: req.body.attribute,
                tags: req.body.tags,
                deal: req.body.deal == null ? 0 : req.body.deal,
                featured: req.body.featured,
                added_by: req.body.added_by,
                point: req.body.point,
                point_exp_date: req.body.point_exp_date
                  ? req.body.point_exp_date
                  : new Date(),
                stock_product:
                  req.body.stock_product != "null"
                    ? req.body.stock_product
                    : "6049f3db426ac9000878ddf6",
                consumable: req.body.consumable,
                seo_title: req.body.seo_title,
                seo_description: req.body.seo_description,
                seo_keywords: req.body.seo_keywords,
                purchase_price: req.body.purchase_price,
                taste: req.body?.taste,
                hot_food_delivery_charges: req.body.hot_food_delivery_charges,
                product_life: req.body.product_life,
              });
              ProductsData.save(function (err) {
                if (err) {
                  res.status(200).send({
                    status: "error",
                    message: err,
                    token: req.token,
                  });
                } else {
                  res.status(200).send({
                    status: "success",
                    message: "Product has been created successfully.",
                    token: req.token,
                  });
                }
              });
            }
          });
        } else {
          res.status(200).send({
            status: "error",
            message: "Select a image to upload.",
          });
        }
      }
    });
  },
