  update_product_status: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["_id"] = req.body.id;
      Products.findOne(where)
        .then((response) => {
          if (response == null) {
            res.status(200).send({
              status: "error",
              message: "Category not found",
              token: req.token,
            });
          } else {
            let active;
            if (response.active == 0) {
              active = 1;
            } else {
              active = 0;
            }

            Products.findOneAndUpdate(
              where,
              {
                active: active,
              },
              {
                new: true,
              }
            )
              .exec()
              .then((response) => {
                const authHeader = req.headers["authorization"];
                const token = authHeader && authHeader.split(" ")[0];
                const decodedToken = jwt.decode(token);
                const userId = decodedToken?.user_id;

                const orderLog = new OrderLog({
                  product: req.body.id || req.query.id,
                  updated_by_user: userId,
                  event: "Product Status Update",
                  event_data: "Active:- " + `${active === 1 ? true : false}`,
                  type: "Product",
                });

                orderLog.save(function (err, response) {
                  if (err) {
                    console.log(err, "ERR");
                  } else {
                    return;
                  }
                });

                res.status(200).send({
                  status: "success",
                  message: "Status updated",
                  token: req.token,
                  active: active,
                });
              })
              .catch((error) => {
                res.status(200).send({
                  status: "error",
                  message: "Something went wrong",
                  token: req.token,
                });
              });
          }
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: "Something went wrong",
            token: req.token,
          });
        });
    }
  },

