  delete_product_image: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["_id"] = req.body.product_id;
      Products.findOne(where).then((response) => {
        let file = response.file;
        file.splice(req.body.image_index, 1);
        let where = {};
        where["_id"] = req.body.product_id;
        Products.findOneAndUpdate(
          where,
          {
            file: file,
          },
          {
            new: true,
          }
        )
          .exec()
          .then(() => {
            const authHeader = req.headers["authorization"];
            const token = authHeader && authHeader.split(" ")[0];
            const decodedToken = jwt.decode(token);
            const userId = decodedToken?.user_id;

            const orderLog = new OrderLog({
              product: req.body.product_id || req.query.product_id,
              updated_by_user: userId,
              event: "Product Image Delete",
              event_data: "Image Delete",
              type: "Product",
            });

            orderLog.save(function (err) {
              if (err) {
                console.log(err, "ERR");
              } else {
                return;
              }
            });
            res.status(200).send({
              status: "success",
              message: "Product has been deleted",
              token: req.token,
            });
          });
      });
    }
  },

