  add_pickup_partner: function (req, res) {
    let where = {};
    where["deleted"] = 0;
    where["mobile"] = req.body.mobile;
    Users.findOne(where)
      .then((response) => {
        if (response != null) {
          res.status(200).send({
            status: "error",
            message: "Mobile already in use.",
          });
        } else {
          let where = {};
          where["deleted"] = 0;
          where["email"] = req.body.email;
          Users.findOne(where)
            .then((response) => {
              if (response != null) {
                res.status(200).send({
                  status: "error",
                  message: "Email address already in use.",
                });
              } else {
                let userdata = new Users({
                  user_type: "pickup_partner",
                  full_name: req.body.name,
                  address: req.body.address,
                  mobile: req.body.mobile,
                  email: req.body.email,
                  cod: req.body.cod,
                  customer_support_city: req.body.customer_support_city
                    ? req.body.customer_support_city.split(",")
                    : null,
                  price_per_kg: req.body.price_per_kg,

                  rate_per_km: req.body.rate_per_km,
                  monthly_fixed_cost: req.body.monthly_fixed_cost,

                  price_per_pack: req.body.price_per_pack,
                  communication_zipcode: req.body.communication_zipcode,
                  service_zipcode: req.body.service_zipcode,
                  bank_name: req.body.bank_name,
                  acc_holder_name: req.body.acc_holder_name,
                  acc_number: req.body.acc_number,
                  branch_code: req.body.branch_code,
                  ifsc: req.body.ifsc,
                  bank_address: req.body.bank_address,
                  active: 1,
                  email_verified: 0,
                  profile_image: "",
                });

                userdata.save(function (err, response) {
                  if (err) {
                    res.status(200).send({
                      status: "error",
                      message: err,
                      token: req.token,
                    });
                  } else {
                    res.status(200).send({
                      status: "success",
                      message: "Account has been created successfully.",
                      data: response,
                    });
                  }
                });
              }
            })
            .catch(() => {
              res.status(200).send({
                status: "error",
                message: "Invalid mobile/password",
              });
            });
        }
      })
      .catch(() => {
        res.status(200).send({
          status: "error",
          message: "Invalid mobile/password",
        });
      });
  },

  pickup_partner_list: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};

      if (req.query.name && req.query.name != "") {
        where["full_name"] = {
          $regex: ".*" + req.query.name,
          $options: "i",
        };
      }

      if (req.query.mobile && req.query.mobile != "") {
        where["mobile"] = {
          $regex: ".*" + req.query.mobile,
          $options: "i",
        };
      }

      if (req.query.active && req.query.active != "") {
        where["active"] = req.query.active;
      }

      where["deleted"] = 0;
      where["user_type"] = "pickup_partner";

      Users.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .populate("parent", "name")
        .sort("full_name")
        .then((response) => {
          Users.find(where).countDocuments(function (err, count) {
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },

