  update_coupon_popup: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      upload_local(req, res, function (error) {
        if (error) {
          res.status(200).send({
            status: "error",
            message: error.code,
            //token: req.token,
          });
        } else {
          const file = req.files[0]; // Get the first (and only) file from the array
          const image_data = {
            fieldname: file.fieldname,
            originalname: file.originalname,
            encoding: file.encoding,
            mimetype: file.mimetype,
            filename: file.filename,
            location: `https://${req.get("host")}/images/${file.filename}`, // Construct the location URL
            size: file.size,
          };

          let where = {};
          where["_id"] = req.query.id;
          coupon_popup
            .findOneAndUpdate(
              where,
              {
                coupon: req.query.coupon,
                file: image_data.location,
                name: req.body.name,
              },
              {
                new: true,
              }
            )
            .exec()
            .then(() => {
              res.status(200).send({
                status: "success",
                message: "Coupon has been updated",
                token: req.token,
              });
              return;
            });
        }
      });
    }
  },

