  delivery_boy_list: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};

      if (req.query.name && req.query.name != "") {
        where["full_name"] = {
          $regex: ".*" + req.query.name,
          $options: "i",
        };
      }

      if (req.query.mobile && req.query.mobile != "") {
        where["mobile"] = {
          $regex: ".*" + req.query.mobile,
          $options: "i",
        };
      }

      if (req.query.active && req.query.active != "") {
        where["active"] = req.query.active;
      }

      if (req.query.parent && req.query.parent != "") {
        where["master"] = req.query.parent;
      }

      if (req.query.id && req.query.id != "") {
        where["master"] = req.query.id;
      }

      where["deleted"] = 0;
      where["user_type"] = "delivery_boy";
      // console.log(where);
      Users.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .populate("parent", "name")
        .populate("master")
        .sort("full_name")
        .then((response) => {
          Users.find(where).countDocuments(function (err, count) {
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },

