  update_review_status: function (req, res) {
    const errors = validationResult(req);

    if (Object.keys(errors.array()).length > 0) {
      return res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    }

    const where = { _id: req.body.id };

    Review.findOne(where)
      .populate("user")
      .then((response) => {
        if (!response) {
          return res.status(200).send({
            status: "error",
            message: "Review not found",
            token: req.token,
          });
        }

        const active = response.active === 0 ? 1 : 0;
        const user_point = Number(response.user.subscription.point);

        Review.findOneAndUpdate(where, { active }, { new: true })
          .exec()
          .then((updatedReview) => {
            const updateWallet = (userId, pointChange, type) => {
              const walletData = new Wallet({
                user: userId,
                point: pointChange,
                type,
                note: "For review",
              });
              walletData.save();
            };

            const updateUserPoints = (userId, pointChange) => {
              const userUpdate = { subscription: { point: pointChange } };
              return Users.findOneAndUpdate(
                { _id: userId, deleted: 0 },
                userUpdate,
                { new: true }
              ).exec();
            };

            const handleReviewStatus = (activeStatus) => {
              Settings.find().then((settings_response) => {
                const reviewValue = settings_response[44].value;
                if (activeStatus === 1) {
                  updateWallet(updatedReview.user._id, reviewValue, 1);
                  updateUserPoints(
                    updatedReview.user._id,
                    reviewValue + user_point
                  );
                } else {
                  updateWallet(updatedReview.user._id, reviewValue, 0);
                  updateUserPoints(
                    updatedReview.user._id,
                    user_point - reviewValue
                  );
                }
              });
            };

            handleReviewStatus(active);

            res.status(200).send({
              status: "success",
              message: "Status updated",
              token: req.token,
              active,
            });
          })
          .catch(() => {
            res.status(200).send({
              status: "error",
              message: "Something went wrong",
              token: req.token,
            });
          });
      })
      .catch(() => {
        res.status(200).send({
          status: "error",
          message: "Something went wrong",
          token: req.token,
        });
      });
  },

