  all_customer_list: async function (req, res) {
    try {
      const errors = validationResult(req);

      // If there are validation errors, return a 400 response
      if (!errors.isEmpty()) {
        return res.status(400).send({
          status: "validation_error",
          errors: errors.array(),
          token: req.token,
        });
      }

      // Build the `where` query
      let where = {
        deleted: 0,
        active: 1,
        user_type: "customer",
      };

      // Add search query condition if present
      if (req.query.q && req.query.q.trim() !== "") {
        where["$or"] = [
          { full_name: { $regex: `.*${req.query.q.trim()}.*`, $options: "i" } },
          { mobile: { $regex: `.*${req.query.q.trim()}.*`, $options: "i" } },
        ];
      }

      console.log(where, "where");

      // Query the database
      const customers = await Users.find(where)
        .sort({ name: 1 }) // Sorting by name in ascending order
        .limit(20)
        .select("full_name mobile email device_token");

      // Send a success response
      // console.log(customers,"customers");
      return res.status(200).send({
        status: "success",
        token: req.token,
        result: customers,
        count: customers.length,
      });
    } catch (error) {
      // Handle errors
      console.error("Error fetching customers:", error);
      return res.status(500).send({
        status: "error",
        message: "An error occurred while fetching customer data.",
        token: req.token,
      });
    }
  },

