  create_shipping: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["name"] = req.query.name;
      where["deleted"] = 0;
      Shipping.findOne(where).then((response) => {
        if (response != null) {
          res.status(200).send({
            status: "error",
            message: "Shipping exist in the database.",
          });
        } else {
          let ShippingData = new Shipping({
            name: req.query.name,
            description_after_ref: req.query.description_after_ref,
            price: req.query.price,
          });
          ShippingData.save(function (err) {
            if (err) {
              res.status(200).send({
                status: "error",
                message: err,
                token: req.token,
              });
            } else {
              res.status(200).send({
                status: "success",
                message: "Shipping has been created successfully..",
              });
            }
          });
        }
      });
    }
  },

