  update_shipping_status: function (req, res) {
    const errors = validationResult(req);

    if (Object.keys(errors.array()).length > 0) {
      return res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    }

    const where = { _id: req.body.id };

    Shipping.findOne(where)
      .then((response) => {
        if (!response) {
          return res.status(200).send({
            status: "error",
            message: "Shipping not found",
            token: req.token,
          });
        }

        const active = response.active === 0 ? 1 : 0;

        Shipping.findOneAndUpdate(where, { active }, { new: true })
          .exec()
          .then(() => {
            res.status(200).send({
              status: "success",
              message: "Status updated",
              token: req.token,
              active,
            });
          })
          .catch(() => {
            res.status(200).send({
              status: "error",
              message: "Something went wrong",
              token: req.token,
            });
          });
      })
      .catch(() => {
        res.status(200).send({
          status: "error",
          message: "Something went wrong",
          token: req.token,
        });
      });
  },
