  update_gateway: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["_id"] = req.query.id;
      Checkout.findOneAndUpdate(
        where,
        {
          gateway: req.query.gateway,
          transactionid: req.query.transactionid,
        },
        {
          new: true,
        }
      )
        .exec()
        .then(() => {
          let msg =
            "Gateway has been changed to " +
            req.query.gateway +
            " by " +
            req.query.by;

          let ordernote = new OrderNote({
            note: msg,
            order: req.query.id,
          });
          ordernote.save(function () {});

          const authHeader = req.headers["authorization"];
          const token = authHeader && authHeader.split(" ")[0];
          const decodedToken = jwt.decode(token);
          const userId = decodedToken?.user_id;

          const orderLog = new OrderLog({
            order: req.query.id,
            updated_by_user: userId,
            event: "Payment Gateway Update",
            event_data: req.query.gateway,
            type: "Order",
          });

          orderLog.save(function (err) {
            if (err) {
              console.log(err, "ERR");
            } else {
              return;
            }
          });
          res.status(200).send({
            status: "success",
            message: "Order gateway has been updated",
            token: req.token,
          });
        });
    }
  },

