  update_customer_cod_status: function (req, res) {
    const errors = validationResult(req);

    if (Object.keys(errors.array()).length > 0) {
      return res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    }

    const where = {};
    where["_id"] = req.body.id;
    where["user_type"] = "customer";

    Users.findOne(where)
      .then((response) => {
        if (response == null) {
          return res.status(200).send({
            status: "error",
            message: "customer not found",
            token: req.token,
          });
        }

        let cod = response.cod === 0 ? 1 : 0;

        Users.findOneAndUpdate(where, { cod }, { new: true })
          .exec()
          .then(() => {
            res.status(200).send({
              status: "success",
              message: "COD status updated",
              token: req.token,
              cod,
            });
          })
          .catch(() => {
            res.status(200).send({
              status: "error",
              message: "Something went wrong",
              token: req.token,
            });
          });
      })
      .catch(() => {
        res.status(200).send({
          status: "error",
          message: "Something went wrong",
          token: req.token,
        });
      });
  },

