  update_bulk_order_status: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      return res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    }

    const where = {};
    where["_id"] = req.body.id;

    BulkOrderModel.findOne(where)
      .then((response) => {
        if (response == null) {
          return res.status(200).send({
            status: "error",
            message: "data not found",
            token: req.token,
          });
        } else {
          let active;
          if (response.active === 0) {
            active = 1;
          } else {
            active = 0;
          }

          BulkOrderModel.findOneAndUpdate(
            where,
            { active: active },
            { new: true }
          )
            .exec()
            .then((response) => {
              const authHeader = req.headers["authorization"];
              const token = authHeader && authHeader.split(" ")[0];
              const decodedToken = jwt.decode(token);
              const userId = decodedToken?.user_id;

              const orderLog = new OrderLog({
                order: req.query.id || req.body.id,
                updated_by_user: userId,
                event: "Update Bulk Order Status",
                event_data: req?.query?.id || req?.body?.id,
                type: "Order",
              });

              orderLog.save((err) => {
                if (err) {
                  return;
                }
                return;
              });

              return res.status(200).send({
                status: "success",
                message: "Status updated",
                token: req.token,
                active: active,
              });
            })
            .catch((error) => {
              return res.status(200).send({
                status: "error",
                message: "Something went wrong",
                token: req.token,
              });
            });
        }
      })
      .catch((error) => {
        return res.status(200).send({
          status: "error",
          message: "Something went wrong",
          token: req.token,
        });
      });
  },

  send_otp: function (req, res) {
    let where = {};
    where["mobile"] = req.body.mobile;
    where["deleted"] = 0;
    Users.findOne(where)
      .then((response) => {
        if (response != null) {
          if (response.user_type == "customer") {
            res.status(200).send({
              status: "error",
              message: "Access denied",
            });
            return;
          } else {
            gen_otp(
              req.body.mobile,
              res,
              (successResponse) => {
                res.status(200).send({
                  status: "success",
                  OTP: successResponse,
                  message: "OTP has been sent.",
                });
              },
              (errorResponse) => {
                res.status(200).send({
                  status: "error",
                  message: errorResponse,
                  OTP: "",
                });
              }
            );
          }
        } else {
          res.status(200).send({
            status: "error",
            message: "mobile number not registered",
            OTP: "",
          });
        }
      })
      .catch(() => {
        res.status(200).send({
          status: "error",
          message: "Invalid mobile",
          OTP: "",
        });
      });
  },

