  state_list_all: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};

      if (req.query.name != "") {
        where["name"] = {
          $regex: ".*" + req.query.name,
          $options: "i",
        };
      }

      if (req.query.active != "") {
        where["active"] = req.query.active;
      }
      if (req.query.lp_head && req.query.lp_head != "") {
        where["lp_head"] = req.query.lp_head;
      }
      if (req.query.lp_manager && req.query.lp_manager != "") {
        where["lp_manager"] = req.query.lp_manager;
      }

      where["deleted"] = 0;

      States.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .sort("name")
        .then((response) => {
          States.find(where).countDocuments(function (err, count) {
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },

  update_state_status: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      const where = {};
      where["_id"] = req.body.id;

      States.findOne(where)
        .then((response) => {
          if (response == null) {
            res.status(200).send({
              status: "error",
              message: "States not found",
              token: req.token,
            });
          } else {
            let active;
            if (response.active == 0) {
              active = 1;
            } else {
              active = 0;
            }

            States.findOneAndUpdate(
              where,
              {
                active: active,
              },
              {
                new: true,
              }
            )
              .exec()
              .then((response) => {
                res.status(200).send({
                  status: "success",
                  message: "Status updated",
                  token: req.token,
                  active: active,
                });
              })
              .catch((error) => {
                res.status(200).send({
                  status: "error",
                  message: "Something went wrong",
                  token: req.token,
                });
              });
          }
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: "Something went wrong",
            token: req.token,
          });
        });
    }
  },

  upload_doc1: function (req, res) {
    upload_local(req, res, function (error) {
      if (error) {
        res.status(200).send({
          status: "error",
          message: error.code,
          //token: req.token,
        });
      } else {
        let where = {};
        where["_id"] = req.body.id;
        Users.findOne(where).then((response) => {
          if (response.doc1 && response.doc1 != "") {
          }

          if (req.files[0]) {
            let where = {};
            where["_id"] = req.body.id;
            const file = req.files[0]; // Get the first (and only) file from the array
            const image_data = {
              fieldname: file.fieldname,
              originalname: file.originalname,
              encoding: file.encoding,
              mimetype: file.mimetype,
              filename: file.filename,
              location: `https://${req.get("host")}/images/${file.filename}`, // Construct the location URL
              size: file.size,
            };

            Users.findOneAndUpdate(
              where,
              {
                doc1: image_data.location,
                doc1_type: req.body.doc1_type,
                update_date: moment().format(),
              },
              {
                new: true,
              }
            )
              .exec()
              .then(() => {
                res.status(200).send({
                  status: "success",
                  message: "Doc 1 has been updated",
                  doc: image_data.location,
                });
              })
              .catch((error) => {
                res.status(200).send({
                  status: "error",
                  message: error,
                  doc: "",
                });
              });
          } else {
            res.status(200).send({
              status: "error",
              message: "Select image",
              doc: "",
            });
          }
        });
      }
    });
  },

