  create_plan: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["deleted"] = 0;
      where["name"] = req.body.name;
      Plan.findOne(where)
        .then((response) => {
          if (response != null) {
            res.status(200).send({
              status: "error",
              message: "Plan exist in the database.",
            });
          } else {
            let plandata = new Plan({
              name: req.body.name,
              city: req.body.city.split(","),
              description: req.body.description,
              price: req.body.price,
              day: req.body.day,
              min_price: req.body.min_price,
              max_price: req.body.max_price,
              discount: req.body.discount,
              point: req.body.point,
            });

            plandata.save(function (err, response) {
              if (err) {
                res.status(200).send({
                  status: "error",
                  message: err,
                  token: req.token,
                });
              } else {
                res.status(200).send({
                  status: "success",
                  message: "Plan has been created successfully.",
                  data: response,
                });
              }
            });
          }
        })
        .catch(() => {
          res.status(200).send({
            status: "error",
            message: "Office name exist in the database.",
          });
        });
    }
  },

  plan_list: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};

      if (req.query.name && req.query.name != "") {
        where["name"] = {
          $regex: ".*" + req.query.name,
          $options: "i",
        };
      }

      if (req.query.active && req.query.active != "") {
        where["active"] = req.query.active;
      }

      where["deleted"] = 0;

      Plan.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .populate("city", "name")
        .sort("name")
        .then((response) => {
          Plan.find(where).countDocuments(function (err, count) {
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },

