  ///// Start Wallet ///////////

  add_wallet: function (req, res) {
    let where = {};
    where["mobile"] = req.body.mobile;
    where["user_type"] = "customer";
    where["deleted"] = 0;
    where["active"] = 1;
    Users.findOne(where).then((response) => {
      let point = response.subscription.point;

      let user_email = response.email;
      let user_mobile = response.mobile;

      if (req.body.type == "1") {
        point = Number(point) + Number(req.body.point);
      } else {
        point = Number(point) - Number(req.body.point);
      }

      let where = {};
      where["mobile"] = req.body.mobile;
      Users.findOneAndUpdate(
        where,
        {
          subscription: {
            point: point,
          },
        },
        {
          new: true,
        }
      ).exec();

      let Walletdata = new Wallet({
        user: response._id,
        point: req.body.point,
        type: req.body.type,
        note: req.body.note,
      });
      Walletdata.save(function (err) {
        if (err) {
          res.status(200).send({
            status: "error",
            message: err,
            token: req.token,
          });
        } else {
          if (req.body.type == 1) {
            let msg =
              "Dear customer, We have added " +
              req.body.point +
              " wallet point in your account. You can redeem this point in your next order. Regards, Tastes2plate";
          } else {
            let msg =
              "Dear customer, We have deducted " +
              req.body.point +
              " wallet point from your account. Regards, Tastes2plate";
          }

          gen_custom_sms(user_mobile, msg);

          axios
            .get(
              "https://webapi.tastes2plate.com/admin/send_email_template?email=" +
                user_email +
                "&msg=" +
                encodeURI(msg),
              {}
            )
            .then(function () {
              //console.log(response.data);
            })
            .catch(function (error) {
              console.log(error);
            });

          if (req.body.type == 1) {
            let parameters = [
              "customer",
              req.body.point,
              // { name: "1", value: "customer" },
              // { name: "2", value: req.body.point },
            ];
            SendWATI("wallet_in", parameters, user_mobile);
          } else {
            let parameters = [
              "customer",
              req.body.point,
              // { name: "1", value: "customer" },
              // { name: "2", value: req.body.point },
            ];
            SendWATI("wallet_out", parameters, user_mobile);
          }

          res.status(200).send({
            status: "success",
            message: "Wallet data created successfully.",
          });
        }
      });
    });
  },

