  inward_list: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["type"] = 0;
      StockTransaction.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .populate("inward_office")
        .populate("outward_office")
        .sort({
          _id: -1,
        })
        .then((response) => {
          StockTransaction.find(where).countDocuments(function (err, count) {
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },

  inward_list2: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["inward_office"] = { $ne: null };

      if (req.query.number != "" && req.query.number) {
        where["bill_no"] = {
          $regex: req.query.number,
        };
      }

      if (
        req.query.start_date != "" &&
        req.query.end_date != "" &&
        req.query.start_date &&
        req.query.end_date
      ) {
        where["created_date"] = {
          $gte: new Date(req.query.start_date).setUTCHours(0, 0, 0, 0),
          $lt: new Date(req.query.end_date).setUTCHours(23, 59, 59, 999),
        };
      }
      if (req.query.start_city != "" && req.query.start_city) {
        where["inward_office"] = req.query.start_city;
      }
      if (req.query.end_city != "" && req.query.end_city) {
        where["customer_city"] = req.query.end_city;
      }
      if (req.query.approved != "" && req.query.approved) {
        where["approved"] = Number(req.query.approved);
      }
      console.log(where);

      PurchaseStockTransaction.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .populate("inward_office")
        .populate("customer_city")
        .sort({
          _id: -1,
        })
        .then((response) => {
          PurchaseStockTransaction.find(where).countDocuments(function (
            err,
            count
          ) {
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
              // where: where
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },

