  update_purchase_inward_product_purchase_price: async function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let qty = await PurchaseStockTransactionProduct.findOne({
        _id: req.body.id,
      });
      await PurchaseStockTransactionProduct.findOneAndUpdate(
        { _id: req.body.id },
        {
          purchase_price: req.body.price,
          total_purchase_price: Number(req.body.price) * Number(qty?.qty),
          total_difference:
            Number(qty?.total ? qty?.total : 0) -
            Number(req.body.price) * Number(qty?.qty ? qty?.qty : 0),
        },
        { new: true }
      )
        .exec()
        .then((response) => {
          res.status(200).send({
            status: "success",
            message: "Purchase Price updated",
            result: response,
            // token: req.token,
            // result: response,
            // totalCount: count,
          });
        });
    }
  },

