  delete_marketing_expense_file: function (req, res) {
    let where = { _id: req.query.id };

    MarketingExpense.findOne(where)
      .then((response) => {
        if (!response) {
          return res.status(404).send({
            status: "error",
            message: "Record not found",
            token: req.token,
          });
        }

        let file = response.file;
        file.splice(req.query.index, 1);

        MarketingExpense.findOneAndUpdate(where, { file: file }, { new: true })
          .exec()
          .then(() => {
            res.status(200).send({
              status: "success",
              message: "File has been deleted",
              token: req.token,
            });
          })
          .catch(() => {
            res.status(500).send({
              status: "error",
              message: "Failed to update record",
              token: req.token,
            });
          });
      })
      .catch(() => {
        res.status(500).send({
          status: "error",
          message: "Failed to fetch record",
          token: req.token,
        });
      });
  },

