  cod_expense_list: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      let where1 = {};

      if (req.query.city && req.query.city != "") {
        where["city"] = mongoose.Types.ObjectId(req.query.city);
        where1["city"] = mongoose.Types.ObjectId(req.query.city);
      }

      if (req.query.office_type && req.query.office_type != "") {
        where["office_type"] = req.query.office_type;
        where1["office_type"] = req.query.office_type;
      }

      if (
        req.query.start_date &&
        req.query.start_date != "" &&
        req.query.end_date &&
        req.query.end_date != ""
      ) {
        where["created_date"] = {
          $gte: new Date(req.query.start_date).setUTCHours(0, 0, 0, 0),
          $lt: new Date(req.query.end_date).setUTCHours(23, 59, 59, 999),
        };
        where1["created_date"] = {
          $gte: new Date(req.query.start_date).setUTCHours(0, 0, 0, 0),
          $lt: new Date(req.query.end_date).setUTCHours(23, 59, 59, 999),
        };
      }

      if (req.query.added_by && req.query.added_by != "") {
        where["added_by"] = mongoose.Types.ObjectId(req.query.added_by);
        where1["added_by"] = mongoose.Types.ObjectId(req.query.added_by);
      }

      if (req.query.office && req.query.office != "") {
        where["office"] = mongoose.Types.ObjectId(req.query.office);
        where1["office"] = mongoose.Types.ObjectId(req.query.office);
      }

      if (req.query.category && req.query.category != "") {
        where["category"] = mongoose.Types.ObjectId(req.query.category);
        where1["category"] = mongoose.Types.ObjectId(req.query.category);
      }

      if (req.query.sub_category && req.query.sub_category != "") {
        where["sub_category"] = mongoose.Types.ObjectId(req.query.sub_category);
        where1["sub_category"] = mongoose.Types.ObjectId(
          req.query.sub_category
        );
      }
      if (!req.query.active_partner) {
        where["active"] = {
          $ne: 3,
        };
        where1["active"] = {
          $ne: 3,
        };
      }
      if (req.query.active && req.query.active != "") {
        where["active"] = Number(req.query.active);
        where1["active"] = Number(req.query.active);
      }

      // if (req.query.active != "") {
      //     where["active"] = req.query.active;
      // }

      where["deleted"] = 0;
      where1["deleted"] = 0;
      where1["payment_recvied"] = {
        to: "int",
      };

      CodPayment.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .populate("office")
        .populate("category")
        .populate("sub_category")
        .populate("city")
        .populate("added_by")
        .populate("action_by")
        .populate("order_id", "timeslot delivery_date status")
        .sort({
          created_date: -1,
        })
        .then((response) => {
          CodPayment.find(where).countDocuments(function (err, count) {
            CodPayment.aggregate([
              { $match: where },
              {
                $group: {
                  _id: {
                    year: { $year: { date: "$created_date" } },
                    month: { $month: { date: "$created_date" } },
                  },
                  sum: { $sum: { $toDouble: "$amount" } },
                },
              },
            ])
              .then((sum_res) => {
                CodPayment.aggregate([
                  { $match: where1 },
                  {
                    $group: {
                      _id: {
                        year: { $year: { date: "$created_date" } },
                        month: { $month: { date: "$created_date" } },
                      },
                      sum: { $sum: { $toDouble: "$payment_recvied" } },
                    },
                  },
                ])
                  .then((sum_res2) => {
                    res.status(200).send({
                      status: "success",
                      result: response,
                      totalCount: count,
                      sum: sum_res[0] ? sum_res[0].sum : 0,
                      payment_recvied: sum_res2[0] ? sum_res2[0].sum : 0,
                      where: where,
                      where1: where1,
                    });
                  })
                  .catch((err) => console.log(err));
              })
              .catch((err) => console.log(err, "E2"));
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },

