  expense_report: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};

      if (req.query.office && req.query.office != "") {
        where["office"] = mongoose.Types.ObjectId(req.query.office);
      }

      if (req.query.office_type && req.query.office_type != "") {
        where["office_type"] = req.query.office_type;
      }

      if (
        req.query.start_date &&
        req.query.start_date != "" &&
        req.query.end_date &&
        req.query.end_date != ""
      ) {
        where["created_date"] = {
          $gte: new Date(req.query.start_date).setUTCHours(0, 0, 0, 0),
          $lt: new Date(req.query.end_date).setUTCHours(23, 59, 59, 999),
        };
      }

      where["active"] = 3;
      where["deleted"] = 0;

      ExpenseCreditRequisition.aggregate([
        { $match: where },
        { $group: { _id: "_id", sum: { $sum: { $toDouble: "$amount" } } } },
      ]).then((credit_requistion_amount) => {
        var credit_requistion_amount = credit_requistion_amount[0]
          ? credit_requistion_amount[0].sum
          : 0;

        CargoExpense.aggregate([
          { $match: where },
          { $group: { _id: "_id", sum: { $sum: { $toDouble: "$amount" } } } },
        ]).then((cargo_amount) => {
          var cargo_amount = cargo_amount[0] ? cargo_amount[0].sum : 0;

          PickupExpense.aggregate([
            { $match: where },
            { $group: { _id: "_id", sum: { $sum: { $toDouble: "$amount" } } } },
          ]).then((pickup_amount) => {
            var pickup_amount = pickup_amount[0] ? pickup_amount[0].sum : 0;

            OtherExpense.aggregate([
              { $match: where },
              {
                $group: { _id: "_id", sum: { $sum: { $toDouble: "$amount" } } },
              },
            ]).then((other_amount) => {
              var other_amount = other_amount[0] ? other_amount[0].sum : 0;

              MarketingExpense.aggregate([
                { $match: where },
                {
                  $group: {
                    _id: "_id",
                    sum: { $sum: { $toDouble: "$amount" } },
                  },
                },
              ]).then((marketing_amount) => {
                var marketing_amount = marketing_amount[0]
                  ? marketing_amount[0].sum
                  : 0;

                TravelExpense.aggregate([
                  { $match: where },
                  {
                    $group: {
                      _id: "_id",
                      sum: { $sum: { $toDouble: "$amount" } },
                    },
                  },
                ]).then((travel_amount) => {
                  var travel_amount = travel_amount[0]
                    ? travel_amount[0].sum
                    : 0;

                  res.status(200).send({
                    result: {
                      credit: credit_requistion_amount,
                      debit:
                        Number(cargo_amount) +
                        Number(pickup_amount) +
                        Number(other_amount) +
                        Number(marketing_amount) +
                        Number(travel_amount),
                      balance:
                        Number(credit_requistion_amount) -
                        (Number(cargo_amount) +
                          Number(pickup_amount) +
                          Number(other_amount) +
                          Number(marketing_amount) +
                          Number(travel_amount)),
                    },
                    status: "success",
                    token: req.token,
                  });
                });
              });
            });
          });
        });
      });
    }
  },

