  all_financial_log: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      if (req.query.partner && req.query.partner != "") {
        where["partner"] = req.query.partner;
      }

      if (req.query.type && req.query.type != "") {
        where["type"] = req.query.type;
      }

      where["order"] = { $ne: null };

      if (
        req.query.start_date &&
        req.query.start_date != "" &&
        req.query.end_date &&
        req.query.end_date != ""
      ) {
        let start = moment(
          moment(req.query.start_date).startOf("day")
        ).toISOString();
        let end = moment(moment(req.query.end_date).endOf("day")).toISOString();

        where["created_date"] = {
          $gte: new Date(start),
          $lt: new Date(end),
        };
      }

      FinancialLog.find(where, null, {
        limit: Number(req.query.limit),
        skip: Number(req.query.page),
      })
        .populate("order")
        .populate("partner")
        .sort({
          created_date: -1,
        })
        .then((response) => {
          FinancialLog.find(where).countDocuments(function (err, count) {
            let where = {};
            if (req.query.partner && req.query.partner != "") {
              where["partner"] = mongoose.Types.ObjectId(req.query.partner);
            }

            if (req.query.type && req.query.type != "") {
              where["type"] = req.query.type;
            }

            if (
              req.query.start_date &&
              req.query.start_date != "" &&
              req.query.end_date &&
              req.query.end_date != ""
            ) {
              let start = moment(
                moment(req.query.start_date).startOf("day")
              ).toISOString();
              let end = moment(
                moment(req.query.end_date).endOf("day")
              ).toISOString();

              where["created_date"] = {
                $gte: new Date(start),
                $lt: new Date(end),
              };
            }

            where["type"] = "IN";

            FinancialLog.aggregate([
              { $match: where },
              {
                $group: {
                  _id: "_id",
                  sum: { $sum: { $toDouble: "$commission" } },
                },
              },
            ]).then((commission_earn) => {
              let where = {};
              if (req.query.partner && req.query.partner != "") {
                where["partner"] = mongoose.Types.ObjectId(req.query.partner);
              }

              if (req.query.type && req.query.type != "") {
                where["type"] = req.query.type;
              }

              if (
                req.query.start_date &&
                req.query.start_date != "" &&
                req.query.end_date &&
                req.query.end_date != ""
              ) {
                let start = moment(
                  moment(req.query.start_date).startOf("day")
                ).toISOString();
                let end = moment(
                  moment(req.query.end_date).endOf("day")
                ).toISOString();

                where["created_date"] = {
                  $gte: new Date(start),
                  $lt: new Date(end),
                };
              }

              where["type"] = "OUT";
              FinancialLog.aggregate([
                { $match: where },
                {
                  $group: {
                    _id: "_id",
                    sum: { $sum: { $toDouble: "$commission" } },
                  },
                },
              ]).then((commission_out) => {
                res.status(200).send({
                  status: "success",
                  result: response,
                  message: "",
                  count: count,
                  commission_earn: commission_earn[0]
                    ? commission_earn[0].sum
                    : 0,
                  commission_out: commission_out[0] ? commission_out[0].sum : 0,
                });
              });
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            result: [],
          });
        });
    }
  },

