  all_travel_log: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      if (req.query.partner && req.query.partner != "") {
        where["partner"] = req.query.partner;
      }

      where["start_address"] = { $ne: "" };

      if (
        req.query.start_date &&
        req.query.start_date != "" &&
        req.query.end_date &&
        req.query.end_date != ""
      ) {
        let start = moment(
          moment(req.query.start_date).startOf("day")
        ).toISOString();
        let end = moment(moment(req.query.end_date).endOf("day")).toISOString();

        where["created_date"] = {
          $gte: new Date(start),
          $lt: new Date(end),
        };
      }

      FinancialLog.find(where, null, {
        limit: Number(req.query.limit),
        skip: Number(req.query.page),
      })
        .populate("order")
        .populate("partner")
        .sort({
          created_date: -1,
        })
        .then((response) => {
          FinancialLog.find(where).countDocuments(function (err, count) {
            let where = {};
            where["order"] = null;
            if (req.query.partner && req.query.partner != "") {
              where["partner"] = mongoose.Types.ObjectId(req.query.partner);
            }

            if (req.query.type && req.query.type != "") {
              where["type"] = req.query.type;
            }

            if (
              req.query.start_date &&
              req.query.start_date != "" &&
              req.query.end_date &&
              req.query.end_date != ""
            ) {
              let start = moment(
                moment(req.query.start_date).startOf("day")
              ).toISOString();
              let end = moment(
                moment(req.query.end_date).endOf("day")
              ).toISOString();

              where["created_date"] = {
                $gte: new Date(start),
                $lt: new Date(end),
              };
            }

            where["paid"] = false;

            FinancialLog.aggregate([
              { $match: where },
              {
                $group: {
                  _id: "_id",
                  sum: { $sum: { $toDouble: "$commission" } },
                },
              },
            ]).then((commission_earn) => {
              let where = {};
              where["paid"] = true;
              where["order"] = null;
              if (req.query.partner && req.query.partner != "") {
                where["partner"] = mongoose.Types.ObjectId(req.query.partner);
              }

              if (req.query.type && req.query.type != "") {
                where["type"] = req.query.type;
              }

              if (
                req.query.start_date &&
                req.query.start_date != "" &&
                req.query.end_date &&
                req.query.end_date != ""
              ) {
                let start = moment(
                  moment(req.query.start_date).startOf("day")
                ).toISOString();
                let end = moment(
                  moment(req.query.end_date).endOf("day")
                ).toISOString();

                where["created_date"] = {
                  $gte: new Date(start),
                  $lt: new Date(end),
                };
              }

              FinancialLog.aggregate([
                { $match: where },
                {
                  $group: {
                    _id: "_id",
                    sum: { $sum: { $toDouble: "$commission" } },
                  },
                },
              ]).then((commission_out) => {
                res.status(200).send({
                  status: "success",
                  result: response,
                  message: "",
                  count: count,
                  commission_earn: commission_earn[0]
                    ? commission_earn[0].sum
                    : 0,
                  commission_out: commission_out[0] ? commission_out[0].sum : 0,
                });
              });
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            result: [],
          });
        });
    }
  },

  update_travel_log_status: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["_id"] = req.body.id;
      FinancialLog.findOne(where).then((response) => {
        if (response == null) {
          res.status(200).send({
            status: "error",
            message: "Log not found",
            token: req.token,
          });
        } else {
          if (!response.paid) {
            let paid = true;
          } else {
            let paid = false;
          }
          FinancialLog.findOneAndUpdate(
            where,
            {
              paid: paid,
            },
            {
              new: true,
            }
          )
            .exec()
            .then(() => {
              res.status(200).send({
                status: "success",
                message: "Status updated",
                token: req.token,
                paid: paid,
              });
            });
        }
      });
    }
  },

  contact_list: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};

      if (req.query.name != "") {
        where["$or"] = [
          {
            name: {
              $regex: ".*" + req.query.name + ".*",
              $options: "i",
            },
          },
          {
            phone: {
              $regex: ".*" + req.query.name + ".*",
              $options: "i",
            },
          },
          {
            email: {
              $regex: ".*" + req.query.name + ".*",
              $options: "i",
            },
          },
        ];
      }

      Contacts.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })

        .sort({
          created_date: -1,
        })
        .then((response) => {
          Contacts.find(where).countDocuments(function (err, count) {
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },
 add_log: function (req, res) {
  upload_local(req, res, function (error) {
    if (error) {
      return res.status(500).json({ status: "error", message: "File upload error", error: error.message });
    }

    try {
      const { user, event, data } = req.body;
      const UsersLogData = new UsersLog({
        user,
        event,
        data,
      });

      UsersLogData.save(function (err) {
        if (err) {
          console.error("Error saving log:", err.message);
          return res.status(500).json({ status: "error", message: "Database save error" });
        }

        return res.status(200).json({ status: "success", message: "Log added successfully" });
      });
    } catch (err) {
      console.error("Unexpected error:", err.message);
      return res.status(500).json({ status: "error", message: "Unexpected error occurred" });
    }
  });
},

