  create_order_log_product: function (req, res) {
    const authHeader = req.headers["authorization"];
    const token = authHeader && authHeader.split(" ")[0];
    const decodedToken = jwt.decode(token);
    const userId = decodedToken?.user_id;

    const orderLog = new OrderLog({
      product: req.body.product ? req.body.product : req.query.product,
      updated_by_user: userId ? userId : req.query.updated_by_user,
      event: req.body.event ? req.body.event : req.query.event,
      event_data: req.body.event_data
        ? req.body.event_data
        : req.query.event_data,
      type: "Product",
    });

    orderLog.save(function (err) {
      if (err) {
        res.status(200).send({
          status: "error",
          message: err,
        });
      } else {
        res.status(200).send({
          status: "success",
          message: "Log created for product change",
        });
      }
    });
  },
