  add_campaign: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["title"] = req.body.title;

      where["active"] = 0;
      CampaignModel.findOne(where).then((respons) => {
        if (respons != null) {
          res.status(200).send({
            status: "error",
            message: "Title already in use. Please try with another title",
          });
        } else {
          multi_upload(req, res, function (error) {
            if (error) {
              res.status(200).send({
                status: "error",
                message: error.code,
                token: req.token,
              });
            } else {
              if (req.files.length > 0) {
                let image_data = [];
                for (let i = 0; i < req.files?.length; i++) {
                  const file = req.files[i]; // Get the first (and only) file from the array
                  const file_data = {
                    fieldname: file.fieldname,
                    originalname: file.originalname,
                    encoding: file.encoding,
                    mimetype: file.mimetype,
                    filename: file.filename,
                    location: `https://${req.get("host")}/images/${
                      file.filename
                    }`, // Construct the location URL
                    size: file.size,
                  };

                  image_data.push(file_data);
                }

                let campaigns = new CampaignModel({
                  title: req.body.title,
                  images: image_data,
                  description: req.body.description,
                });

                campaigns.save(function (err) {
                  if (err) {
                    res.status(200).send({
                      status: "error",
                      message: err,
                    });
                  } else {
                    res.status(200).send({
                      status: "success",
                      message: "Campaign has been created successfully.",
                    });
                  }
                });
              } else {
                let campaigns = new CampaignModel({
                  title: req.body.title,
                  description: req.body.description,
                });

                campaigns.save(function (err) {
                  if (err) {
                    res.status(200).send({
                      status: "error",
                      message: err,
                    });
                  } else {
                    res.status(200).send({
                      status: "success",
                      message: "Campaign has been created successfully.",
                    });
                  }
                });
              }
            }
          });
        }
      });
    }
  },
  delete_campaign_image: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["_id"] = req.body.id;
      CampaignModel.findOne(where).then((response) => {
        let file = response.images;
        file.splice(req.body.image_index, 1);
        let where = {};
        where["_id"] = req.body.id;
        CampaignModel.findOneAndUpdate(
          where,
          {
            images: file,
          },
          {
            new: true,
          }
        )
          .exec()
          .then(() => {
            res.status(200).send({
              status: "success",
              message: "Campaign image has been deleted",
            });
          });
      });
    }
  },
