  send_campaign_email: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["_id"] = req.body.campaign;
      let success;
      let transporter = nodemailer.createTransport({
        host: SMTP_HOST,
        port: SMTP_PORT,
        //secure: process.env.SMTP_SECURE, // true for 465, false for other ports
        auth: {
          user: SMTP_USERNAME, // generated ethereal user
          pass: SMTP_PASSWORD, // generated ethereal password
        },
      });
      CampaignModel.findOne(where).then((response) => {
        const attachments = response?.images?.map((file) => {
          return { filename: file.originalname, path: file.location };
        });
        for (let i = 0; i < req.body.user?.length; i++) {
          Users.findOne({ _id: req.body.user[i] }).then((respon) => {
            if (respon?.email && req.body.email) {
              transporter
                .sendMail({
                  from: EMAIL_FROM, // sender address
                  to: respon?.email, // list of receivers
                  subject: response?.title, // Subject line
                  html: response?.description, // html body
                  attachments: attachments,
                })
                .then((sa) => {
                  success = sa;
                  console.log(i, respon?.email, req.body.user?.length);
                  return;
                })
                .catch((error) => {
                  console.log(error);
                });
            }
          });
        }
      });
      res.status(200).send({
        status: "success",
        message: "Email send successfully",
        result: success,
      });
    }
  },
  send_campaign_push: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["_id"] = req.body.campaign;

      CampaignModel.findOne(where).then((response) => {
        Users.find({
          _id: {
            $in: req.body.user,
          },
        }).then((respon) => {
          let device_token = [];
          for (let i = 0; i < respon?.length; i++) {
            if (respon[i]?.device_token) {
              device_token.push(respon[i].device_token);
            }
          }
          // console.log(response, device_token, "USERDETAILS")
          if (req.body.push && device_token) {
            //FirebaseAdmin
            const attachments = response?.images?.map((file) => {
              return file.location;
            });
            const serviceAccount = require("../../taste2plate-1be43-firebase-adminsdk-h69yr-d3d68155c3.json");
            if (!FirebaseAdmin.apps.length) {
              FirebaseAdmin.initializeApp({
                credential: FirebaseAdmin.credential.cert(serviceAccount),
              });
            }
            const registrationTokens = device_token;
            const message = {
              notification: {
                title: response?.title,
                body: response?.description?.replace(/<[^>]+>/g, ""),
                image: attachments && attachments[0],
              },
              //topic: "general",
            };
            FirebaseAdmin.messaging()
              .sendToDevice(registrationTokens, message, { priority: "high" })
              .then((se) => {
                res.status(200).send({
                  status: "success",
                  message: "Push send successfully",
                  result: se,
                  body: response?.description?.replace(/<[^>]+>/g, ""),
                });
              })
              .catch((error) => {
                res.status(200).send({
                  status: "error",
                  message: error.message,
                });
              });
          }
        });
      });
    }
  },
