  create_survey: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
      });
    } else {
      let where = {};
      where["title"] = req.body.title;
      SurveyModel.findOne(where).then((response) => {
        if (response != null) {
          res.status(200).send({
            status: "error",
            message: "Survey with this title already exist.",
          });
        } else {
          let survey = new SurveyModel({
            title: req.body.title,
            survey: JSON.parse(JSON.stringify(JSON.parse(req.body.survey))),
            start_date: req.body.start_date,
            end_date: req.body.end_date,
            assigned_to: req.body.assigned_to
              ? req.body.assigned_to.split(",")
              : null,
            event_type: Number(req.body.event_type),
          });

          survey.save(function (err, response) {
            if (err) {
              res.status(200).send({
                status: "error",
                message: err,
              });
            } else {
              res.status(200).send({
                status: "success",
                message: "Survey has been created successfully.",
                result: response,
              });
            }
          });
        }
      });
    }
  },
