  update_answer_call_update: async function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      return res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
      });
    }

    let where = {};
    where["_id"] = req.body.id;
    where["filled"] = 0;

    try {
      // Fetch the specific SurveyAnswer based on ID
      const response = await SurveyAnswer.findOne(where);

      if (!response) {
        return res.status(404).send({
          status: "error",
          message: "SurveyAnswer not found.",
        });
      }

      const userId = response.user;

      // Get the timestamp for 24 hours ago
      const last24Hours = new Date();
      last24Hours.setHours(last24Hours.getHours() - 24);

      // Build the update object based on call1, call2, call3
      let update = {};
      if (req.body.call1) {
        update["call1"] = new Date();
      }
      if (req.body.call2) {
        update["call2"] = new Date();
      }
      if (req.body.call3) {
        update["call3"] = new Date();
        update["filled"] = 2;
      }

      // Update all SurveyAnswer entries for this user in the last 24 hours
      const result = await SurveyAnswer.updateMany(
        {
          user: userId,
          updatedAt: { $gte: last24Hours },
        },
        {
          $set: update,
        }
      );
      if (req.body.call1 || req.body.call2) {
        // If any of the calls were updated, send a success response
        res.status(200).send({
          status: "success",
          message: "call received  successfully.",
        });
      } else {
        res.status(200).send({
          status: "success",
          message: "Call not received Updated.",
        });
      }
    } catch (err) {
      console.error(err);
      res.status(500).send({
        status: "error",
        message: "An error occurred while updating survey answers.",
      });
    }
  },
  survey_answer_list: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
      });
    } else {
      let where = {};
      if (req.body.filled) {
        where["filled"] = Number(req.body.filled);
      }
      if (req.body.survey) {
        where["survey"] = req.body.survey;
      }
      if (req.body.assigned_to) {
        where["assigned_to"] = req.body.assigned_to;
      }
      SurveyAnswer.find(where, null, {
        limit: parseInt(req.body.limit),
        skip: parseInt(req.body.page),
      })
        .populate("user assigned_to survey")
        .populate("product")
        .sort("-updatedAt")
        .then((response) => {
          SurveyAnswer.find(where).countDocuments(function (err, count) {
            res.status(200).send({
              status: "success",
              message: "Data found.",
              result: response,
              count: count,
            });
          });
        })
        .catch((err) => console.log(err, "SURvEYY Error"));
    }
  },
