  ghar_ka_khana_category_list: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};

      if (req.query.name != "") {
        where["name"] = {
          $regex: ".*" + req.query.name,
          $options: "i",
        };
      }

      if (req.query.active != "") {
        where["active"] = req.query.active;
      }

      if (req.query.parent != "") {
        where["parent"] = req.query.parent;
      }

      where["deleted"] = 0;

      GharKaKhanaCategories.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .populate("parent", "name")
        .sort("name")
        .then((response) => {
          GharKaKhanaCategories.find(where).countDocuments(function (
            err,
            count
          ) {
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },

  ghar_ka_khana_update_category_status: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["_id"] = req.body.id;
      GharKaKhanaCategories.findOne(where)
        .then((response) => {
          if (response == null) {
            res.status(200).send({
              status: "error",
              message: "Category not found",
              token: req.token,
            });
          } else {
            if (response.active == 0) {
              let active = 1;
            } else {
              let active = 0;
            }
            GharKaKhanaCategories.findOneAndUpdate(
              where,
              {
                active: active,
              },
              {
                new: true,
              }
            )
              .exec()
              .then(() => {
                res.status(200).send({
                  status: "success",
                  message: "Status updated",
                  token: req.token,
                  active: active,
                });
              })
              .catch(() => {
                res.status(200).send({
                  status: "error",
                  message: "Something went wrong",
                  token: req.token,
                });
              });
          }
        })
        .catch(() => {
          res.status(200).send({
            status: "error",
            message: "Something went wrong",
            token: req.token,
          });
        });
    }
  },

