  ghar_ka_kahana_add_slider: function (req, res) {
    if (!req.query.name || req.query.name == "") {
      res.status(200).send({
        status: "error",
        message: "Enter brand name",
        token: req.token,
      });
    } else {
      upload2(req, res, function (error) {
        if (error) {
          res.status(200).send({
            status: "error",
            message: "Something went wrong",
            // token: req.token,
            error: error,
          });
        } else {
          if (req.files.length > 0) {
            let upload2 = null;
            let upload1 = null;

            let image_data = [];
            for (let i = 0; i < req.files?.length; i++) {
              const file = req.files[i]; // Get the first (and only) file from the array
              const file_data = {
                fieldname: file.fieldname,
                originalname: file.originalname,
                encoding: file.encoding,
                mimetype: file.mimetype,
                filename: file.filename,
                location: `https://${req.get("host")}/images/${file.filename}`, // Construct the location URL
                size: file.size,
              };

              image_data.push(file_data);
            }

            if (image_data[1].location) {
              upload2 = image_data[1] ? image_data[1].location : null;
            }
            if (image_data[0].location) {
              upload1 = image_data[0] ? image_data[0].location : null;
            }
            let Sliderdata = new GharKaKhanaSlider({
              // city: req.query.city,
              name: req.query.name,
              file: upload1,
              desktop_file: upload2,
            });

            Sliderdata.save(function (err) {
              if (err) {
                res.status(200).send({
                  status: "error",
                  message: err,
                  token: req.token,
                });
              } else {
                res.status(200).send({
                  status: "success",
                  message: "Slider has been created successfully.",
                });
              }
            });
          } else {
            res.status(200).send({
              status: "error",
              message: "Select image to upload.",
            });
          }
        }
      });
    }
  },

