  ghar_ka_khana_fetch_orders: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      if (req.query.pickup_city) {
        where["source_city"] = req.query.pickup_city;
      }
      if (req.query.destination_city) {
        where["destination_city"] = req.query.destination_city;
      }

      if (!req.query.status && req.query.status == "") {
        where["status"] = "booking_confirmed";
      } else {
        where["status"] = req.query.status;
      }
      if (
        req.query.start_date &&
        req.query.start_date != "" &&
        req.query.end_date &&
        req.query.end_date != ""
      ) {
        // let start = moment(moment(req.query.start_date)).subtract(1, "days").format("YYYY-MM-DD");
        // let end = moment(moment(req.query.end_date)).add(1, "days").format("YYYY-MM-DD");

        let start = moment(
          moment(req.query.start_date).startOf("day")
        ).toISOString();
        let end = moment(moment(req.query.end_date).endOf("day")).toISOString();

        where["delivery_date"] = {
          $gte: new Date(start),
          $lt: new Date(end),
        };
      }
      if (req.query.orderid) {
        where["orderid"] = req.query.orderid;
      }
      if (req.query.browser_filter && req.query.browser_filter != "") {
        where["browser"] = req.query.browser_filter;
      }

      if (req.query.gateway && req.query.gateway != "") {
        where["gateway"] = req.query.gateway;
      }
      if (req.query.delivery_mode) {
        where["delivery_type"] = req.query.delivery_mode;
      }
      if (
        req.query?.filter_new_repeat &&
        Number(req.query?.filter_new_repeat) === 1
      ) {
        where["order_count"] = 1;
      } else if (
        req.query.filter_new_repeat &&
        Number(req.query?.filter_new_repeat) === 2
      ) {
        where["order_count"] = {
          $gt: 2,
        };
      }
      where["order_confirmation"] = 1;
      where["deleted"] = 0;
      Users.findOne({
        user_type: "customer",
        mobile: {
          $regex: req.query.mobile,
          $options: "i",
        },
      }).then(function (mobile_data) {
        Users.findOne({
          user_type: "customer",
          email: {
            $regex: ".*" + req.query.email,
            $options: "i",
          },
        })
          .then(function (email_data) {
            if (mobile_data && req.query.mobile != "") {
              where["user"] = mobile_data._id;
            } else if (mobile_data === null && req.query.mobile) {
              where["user"] = null;
            }

            if (email_data && req.query.email != "") {
              where["user"] = email_data._id;
            } else if (email_data === null && req.query.email) {
              where["user"] = null;
            }
            // Further operations with 'where' object
          })
          .then(() => {
            GharKakhanaOrders.find(where, null, {
              limit: parseInt(req.query.limit),
              skip: parseInt(req.query.page),
            })
              .sort("-createdAt")
              .populate("user")
              .populate("source_location")
              .populate("products.category")
              .populate("products.sub_category")
              .populate("destination_location")
              .populate("pickup_partner delivery_partner")
              .populate("delivery_boy")
              .populate("pickup_boy")
              .then((response) => {
                GharKakhanaOrders.find(where).countDocuments(function (
                  err,
                  count
                ) {
                  if (err) {
                    console.log(err);
                  }
                  res.status(200).send({
                    status: "success",
                    result: response,
                    totalCount: count,
                  });
                });
              })
              .catch((err) => console.log(err));
          });
      });
      // console.log(where,"WHERE2")
    }
  },
