  // Gift Start
  create_gift: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        // token: req.token,
      });
    } else {
      multi_upload(req, res, function (error2) {
        console.log("error2", error2);
        if (error2) {
          req.status(200).send({
            status: "error",
            message: error2,
          });

          return;
        }

        let where = {};
        where["name"] = req.body.name;
        where["gift_type"] = req.body.type;
        GiftModel.findOne(where).then((response) => {
          if (response != null) {
            res.status(200).send({
              status: "error",
              message: "Gift exist in the database.",
              token: req.token,
            });
          } else {
            let image_data = [];
            for (let i = 0; i < req.files?.length; i++) {
              const file = req.files[i]; // Get the first (and only) file from the array
              const file_data = {
                fieldname: file.fieldname,
                originalname: file.originalname,
                encoding: file.encoding,
                mimetype: file.mimetype,
                filename: file.filename,
                location: `https://${req.get("host")}/images/${file.filename}`, // Construct the location URL
                size: file.size,
              };

              image_data.push(file_data);
            }

            let GiftData = new GiftModel({
              name: req.body.name,
              gift_type: req.body.type,
              description: req.body.description,
              images: image_data,
              video: req.body.video,
              minExpend: req.body.minExpend,
              maxExpend: req.body.maxExpend,
              dateValidFrom: req.body.start_date,
              dateValidTo: req.body.end_date,
              active: req.body.active,
            });
            GiftData.save(function (err) {
              if (err) {
                res.status(200).send({
                  status: "error",
                  message: err,
                  token: req.token,
                });
              } else {
                res.status(200).send({
                  status: "success",
                  message: "Gift has been created successfully.",
                });
              }
            });
          }
        });
      });
    }
  },
  gift_list: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};

      if (req.query.name != "") {
        where["name"] = {
          $regex: ".*" + req.query.name,
          $options: "i",
        };
      }
      if (req.query.active != "") {
        where["active"] = req.query.active;
      }

      where["deleted"] = 0;

      GiftModel.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .sort("name")
        .populate("gift_type")
        .exec()
        .then((response) => {
          GiftModel.countDocuments(where, function (err, count) {
            if (err) {
              throw err;
            }
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error.message,
            token: req.token,
          });
        });
    }
  },

  update_gift_status: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["_id"] = req.body.id;
      GiftModel.findOne(where)
        .then((response) => {
          if (response == null) {
            res.status(200).send({
              status: "error",
              message: "Gift not found",
              token: req.token,
            });
          } else {
            if (response.active == 0) {
              let active = 1;
            } else {
              let active = 0;
            }
            GiftModel.findOneAndUpdate(
              where,
              {
                active: active,
              },
              {
                new: true,
              }
            )
              .exec()
              .then(() => {
                res.status(200).send({
                  status: "success",
                  message: "Status updated",
                  token: req.token,
                  active: active,
                });
              })
              .catch(() => {
                res.status(200).send({
                  status: "error",
                  message: "Something went wrong",
                  token: req.token,
                });
              });
          }
        })
        .catch(() => {
          res.status(200).send({
            status: "error",
            message: "Something went wrong",
            token: req.token,
          });
        });
    }
  },
