  delete_gift_image: function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      where["_id"] = req.body.gift_id;
      GiftModel.findOne(where).then((response) => {
        let file = response.images;
        file.splice(req.body.image_index, 1);
        let where = {};
        where["_id"] = req.body.gift_id;
        GiftModel.findOneAndUpdate(
          where,
          {
            images: file,
          },
          {
            new: true,
          }
        ).then(() => {
          res.status(200).send({
            status: "success",
            message: "Gift has been deleted",
            token: req.token,
          });
        });
      });
    }
  },
  update_gift: function (req, res) {
    multi_upload(req, res, function (error) {
      if (error) {
        res.status(200).send({
          status: "error",
          message: error.code,
          token: req.token,
        });
      } else {
        if (!req.body.name || req.body.name == "") {
          res.status(200).send({
            status: "error",
            message: "Enter gift name",
            token: req.token,
          });
          return false;
        }
        if (!req.body.id || req.body.id == "") {
          res.status(200).send({
            status: "error",
            message: "Please send gift id",
            token: req.token,
          });
          return false;
        }

        ////
        if (req.files.length > 0) {
          let where = {};
          where["_id"] = req.body.id;
          let image_data = [];
          for (let i = 0; i < req.files?.length; i++) {
            const file = req.files[i]; // Get the first (and only) file from the array
            const file_data = {
              fieldname: file.fieldname,
              originalname: file.originalname,
              encoding: file.encoding,
              mimetype: file.mimetype,
              filename: file.filename,
              location: `https://${req.get("host")}/images/${file.filename}`, // Construct the location URL
              size: file.size,
            };

            image_data.push(file_data);
          }

          GiftModel.findOne(where).then((response) => {
            let file = response.images;
            image_data.forEach(function (arrayItem) {
              file.push(arrayItem);
            });

            let where = {};
            where["_id"] = req.body.id;
            GiftModel.findOneAndUpdate(
              where,
              {
                name: req.body.name,
                gift_type: req.body.type,
                description: req.body.description,
                images: file,
                video: req.body.video,
                minExpend: req.body.minExpend,
                maxExpend: req.body.maxExpend,
                dateValidFrom: req.body.start_date,
                dateValidTo: req.body.end_date,
              },
              {
                new: true,
              }
            )
              .exec()
              .then(() => {
                res.status(200).send({
                  status: "success",
                  message: "Gift has been updated",
                  token: req.token,
                });
              });
          });
        } else {
          let where = {};
          where["_id"] = req.body.id;
          GiftModel.findOneAndUpdate(
            where,
            {
              name: req.body.name,
              gift_type: req.body.type,
              description: req.body.description,
              video: req.body.video,
              minExpend: req.body.minExpend,
              maxExpend: req.body.maxExpend,
              dateValidFrom: req.body.start_date,
              dateValidTo: req.body.end_date,
            },
            {
              new: true,
            }
          )
            .exec()
            .then(() => {
              res.status(200).send({
                status: "success",
                message: "Gift has been updated",
                token: req.token,
              });
            });
        }
      }
    });
  },

