  // TimeSlot

  add_TimeSlot: async function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    }
    function extractStartTime(timeSlot) {
      let startTime = timeSlot.split("-")[0];
      return parseInt(startTime.replace(":", ""));
    }
    try {
      // Find the latest timeslot document
      let timeslot = await TimeSlots.findOne(
        {},
        {},
        { sort: { createdAt: -1 } }
      ).exec();

      let slots = req.body.slot;

      if (!timeslot) {
        // If no timeslot exists, create a new one with the provided slot
        let newTimeslot = await TimeSlots.create({ timeslots: [slots] });
        return res.status(200).json({
          status: 1,
          message: "Slot Added Successfully",
          data: newTimeslot,
        });
      }
      timeslot.timeslots.push(slots);
      timeslot.timeslots.sort(
        (a, b) => extractStartTime(a) - extractStartTime(b)
      );

      let updatedTimeslot = await timeslot.save();
      return res.status(200).json({
        status: 1,
        message: "Slot Added Successfully",
        data: updatedTimeslot,
      });
    } catch (err) {
      console.error(err);
      return res
        .status(500)
        .json({ status: "error", message: "Error adding timeslot" });
    }
  },
  delete_TimeSlot: async function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    }
    try {
      const timeslotId = req.body.timeslotId;
      const slotIndex = req.body.slotIndex;
      const timeslot = await TimeSlots.findById(timeslotId);

      if (!timeslot) {
        return res
          .status(404)
          .json({ status: "error", message: "Timeslot not found" });
      }

      timeslot.timeslots.splice(slotIndex, 1);
      await timeslot.save();

      return res
        .status(200)
        .json({ status: 1, message: "Slot deleted successfully" });
    } catch (error) {
      console.error(error);
      return res
        .status(500)
        .json({ status: "error", message: "Error deleting slot" });
    }
  },
  get_TimeSlot: async function (req, res) {
    const errors = validationResult(req);

    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    }
    function convertTo12HourFormat(time) {
      const [hours, minutes] = time.split(":");
      const period = hours >= 12 ? "PM" : "AM";
      const hour12 = hours % 12 || 12;

      // Construct the 12-hour format time string
      return `${hour12}:${minutes} ${period}`;
    }
    try {
      const timeslots = await TimeSlots.find().exec();
      const timeslots12HourFormat = timeslots.map((timeslot) => ({
        _id: timeslot._id,
        timeslots: timeslot.timeslots.map((slot) => {
          const [startTime, endTime] = slot.split("-");
          return `${convertTo12HourFormat(startTime)} - ${convertTo12HourFormat(
            endTime
          )}`;
        }),
      }));

      // Respond with timeslots in 12-hour format
      return res.status(200).json({ timeslots: timeslots12HourFormat });
    } catch (error) {
      console.error(error);
      return res.status(500).json({ error: "Error fetching timeslots" });
    }
  },
