  ///// Start Second Header ///////////

  add_second_header: function (req, res) {
    if (!req.query.heading || req.query.heading == "") {
      res.status(200).send({
        status: "error",
        message: "Enter Header",
        token: req.token,
      });
    } else {
      upload2(req, res, function (error) {
        if (error) {
          res.status(200).send({
            status: "error",
            message: "Something went wrong",
            // token: req.token,
            error: error,
          });
        } else {
          if (req.files?.length > 0) {
            let upload2 = null;
            let upload1 = null;

            let image_data = [];
            for (let i = 0; i < req.files?.length; i++) {
              const file = req.files[i]; // Get the first (and only) file from the array
              const file_data = {
                fieldname: file.fieldname,
                originalname: file.originalname,
                encoding: file.encoding,
                mimetype: file.mimetype,
                filename: file.filename,
                location: `https://${req.get("host")}/images/${file.filename}`, // Construct the location URL
                size: file.size,
              };

              image_data.push(file_data);
            }

            if (image_data[1]?.location) {
              upload2 = image_data[1] ? image_data[1].location : null;
            }
            if (image_data[0]?.location) {
              upload1 = image_data[0] ? image_data[0].location : null;
            }
            let secondHeader = new SecondHeader({
              heading: req.query.heading,
              sub_heading: req.query.sub_heading,
              image: upload1,
              desktop_image: upload2,
              cuisine: req.query?.cuisine ? req.query?.cuisine : null,
            });

            secondHeader.save(function (err) {
              if (err) {
                res.status(200).send({
                  status: "error",
                  message: err,
                  token: req.token,
                });
              } else {
                res.status(200).send({
                  status: "success",
                  message: "Second Header has been created successfully.",
                });
              }
            });
          } else {
            res.status(200).send({
              status: "error",
              message: "Select image to upload.",
            });
          }
        }
      });
    }
  },

