  second_header_update: function (req, res) {
    if (!req.query.heading || req.query.heading == "") {
      res.status(200).send({
        status: "error",
        message: "Enter Heading",
        token: req.token,
      });
    }
    if (!req.query.id || req.query.id == "") {
      res.status(200).send({
        status: "error",
        message: "Enter Heading id",
        token: req.token,
      });
    } else {
      // console.log(req.query, "UPDATE SLIDER")
      upload2(req, res, function () {
        if (req.files?.length == 0) {
          let where = {};
          where["_id"] = req.query.id;
          SecondHeader.findOneAndUpdate(
            where,
            {
              heading: req.query.heading,
              sub_heading: req.query.sub_heading,
              cuisine: req.query.cuisine,
            },
            {
              new: true,
            }
          )
            .exec()
            .then(() => {
              res.status(200).send({
                status: "success",
                message: "Heading has been updated",
                token: req.token,
              });
              return;
            });
          //
        } else {
          let where = {};
          where["_id"] = req.query.id;

          let updatedata = {};
          updatedata["heading"] = req.query.heading;

          updatedata["sub_heading"] = req.query.sub_heading;

          let image_data = [];
          for (let i = 0; i < req.files?.length; i++) {
            const file = req.files[i]; // Get the first (and only) file from the array
            const file_data = {
              fieldname: file.fieldname,
              originalname: file.originalname,
              encoding: file.encoding,
              mimetype: file.mimetype,
              filename: file.filename,
              location: `https://${req.get("host")}/images/${file.filename}`, // Construct the location URL
              size: file.size,
            };

            image_data.push(file_data);
          }

          if (image_data[1]?.location) {
            updatedata["desktop_image"] = image_data[1]?.location;
          }

          if (image_data[0]?.location) {
            updatedata["image"] = image_data[0]?.location;
          }
          updatedata["cuisine"] = req.query.cuisine;

          SecondHeader.findOneAndUpdate(where, updatedata, {
            new: true,
          })
            .exec()
            .then(() => {
              res.status(200).send({
                status: "success",
                message: "Second Header has been updated",
                token: req.token,
              });
            });
        }
      });
    }
  },

