  fetch_daily_activity: async function (req, res) {
    const errors = validationResult(req);
    if (Object.keys(errors.array()).length > 0) {
      res.status(200).send({
        status: "validation_error",
        errors: errors.array(),
        token: req.token,
      });
    } else {
      let where = {};
      if (req.query.mobile) {
        let user = await Users.findOne({
          mobile: req.query.mobile,
          deleted: 0,
          user_type: { $ne: "customer" },
        });
        where["user_id"] = user?._id;
      }

      if (req.query.email) {
        let user = await Users.findOne({
          email: req.query.email,
          deleted: 0,
          user_type: { $ne: "customer" },
        });
        where["user_id"] = user?._id;
      }
      if (req.query.partners) {
        where["user_id"] = req.query.partners;
      }

      if (req.query.page_visit) {
        where["page"] = req.query.page_visit;
      }

      if (req.query.devices) {
        where["device"] = req.query.devices;
      }

      where["type"] = {
        $ne: "Logistic App",
      };

      if (
        req.query.start_date != "" &&
        req.query.end_date != "" &&
        req.query.start_date &&
        req.query.end_date
      ) {
        where["createdAt"] = {
          $gte: new Date(req.query.start_date).setUTCHours(0, 0, 0, 0),
          $lt: new Date(req.query.end_date).setUTCHours(23, 59, 59, 999),
        };
      }

      DailyActivity.find(where, null, {
        limit: parseInt(req.query.limit),
        skip: parseInt(req.query.page),
      })
        .populate("user_id", "full_name mobile email")
        .sort({
          createdAt: -1,
        })
        .then((response) => {
          DailyActivity.find(where).countDocuments(function (err, count) {
            res.status(200).send({
              status: "success",
              token: req.token,
              result: response,
              totalCount: count,
            });
          });
        })
        .catch((error) => {
          res.status(200).send({
            status: "error",
            message: error,
            token: req.token,
          });
        });
    }
  },
